package com.demo.web.dto.Auth;

import com.demo.web.model.Auth.user; import javax.crypto.SecretKey; public class AuthLoginResponse { private boolean success; private String errorMessage; private String infoMessage; private user user; private SecretKey masterKey; private String rememberMeToken; private String redirectUrl; public boolean isSuccess() { return success; } public void setSuccess(boolean success) { this.success = success; } public String getErrorMessage() { return errorMessage; } public void setErrorMessage(String errorMessage) { this.errorMessage = errorMessage; } public String getInfoMessage() { return infoMessage; } public void setInfoMessage(String infoMessage) { this.infoMessage = infoMessage; } public user getUser() { return user; } public void setUser(user user) { this.user = user; } public SecretKey getMasterKey() { return masterKey; } public void setMasterKey(SecretKey masterKey) { this.masterKey = masterKey; } public String getRememberMeToken() { return rememberMeToken; } public void setRememberMeToken(String rememberMeToken) { this.rememberMeToken = rememberMeToken; } public String getRedirectUrl() { return redirectUrl; } public void setRedirectUrl(String redirectUrl) { this.redirectUrl = redirectUrl; } }
